args.command:
cat profile.json && echo && echo "=== Validation ===" && node -e "
const schema = require('./schema.json');
const profile = require('./profile.json');
const Ajv = require('ajv');
const ajv = new Ajv();
const validate = ajv.compile(schema);
const valid = validate(profile);
if (valid) {
  console.log('✓ Validates against schema');
  console.log('✓ Top-level keys:', Object.keys(profile).sort().join(', '));
  console.log('✓ Owner keys:', Object.keys(profile.owner).sort().join(', '));
  console.log('✓ id:', profile.id);
  console.log('✓ owner.name:', profile.owner.name);
  console.log('✓ owner.team:', profile.owner.team);
} else {
  console.log('✗ Validation failed:', validate.errors);
}
"
